import React, { useState, useEffect } from 'react';
import './App.css';

const API_BASE = 'http://localhost/Weather-Alert';

// Grenada parishes data
const PARISHES = [
  { id: 'saint-george', name: "Saint George", capital: "St. George's", lat: 12.0561, lon: -61.7486 },
  { id: 'saint-andrew', name: "Saint Andrew", capital: "Grenville", lat: 12.1167, lon: -61.6167 },
  { id: 'saint-david', name: "Saint David", capital: "St. David's", lat: 12.0333, lon: -61.7000 },
  { id: 'saint-john', name: "Saint John", capital: "Gouyave", lat: 12.1667, lon: -61.7333 },
  { id: 'saint-mark', name: "Saint Mark", capital: "Victoria", lat: 12.1833, lon: -61.7000 },
  { id: 'saint-patrick', name: "Saint Patrick", capital: "Sauteurs", lat: 12.2167, lon: -61.6333 },
  { id: 'carriacou', name: "Carriacou", capital: "Hillsborough", lat: 12.4789, lon: -61.4492 }
];

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState('login');
  const [currentTab, setCurrentTab] = useState('weather');

  // Form states
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Weather state
  const [weather, setWeather] = useState(null);
  const [parish, setParish] = useState(PARISHES[0]);
  const [weatherLoading, setWeatherLoading] = useState(false);
  const [isDark, setIsDark] = useState(false);

  // Alert state
  const [alertHistory, setAlertHistory] = useState([]);
  const [alertPrefs, setAlertPrefs] = useState({ storms: true, rain: true });

  // Admin state
  const [users, setUsers] = useState([]);
  const [broadcastMessage, setBroadcastMessage] = useState('');
  const [sending, setSending] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('auth_token');
    const storedUser = localStorage.getItem('user');

    if (token && storedUser) {
      const userData = JSON.parse(storedUser);
      setUser(userData);
      setPage('dashboard');
      if (userData.alerts) {
        setAlertPrefs(userData.alerts);
      }
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    if (user && currentTab === 'weather') {
      fetchWeather();
    }
  }, [user, parish, currentTab]);

  useEffect(() => {
    if (user && currentTab === 'alerts') {
      loadAlertHistory();
    }
  }, [user, currentTab]);

  useEffect(() => {
    if (user && user.role === 'admin' && currentTab === 'admin') {
      loadUsers();
    }
  }, [user, currentTab]);

  const fetchWeather = async () => {
    setWeatherLoading(true);
    try {
      const params = new URLSearchParams({
        latitude: parish.lat,
        longitude: parish.lon,
        current: 'temperature_2m,relative_humidity_2m,precipitation,rain,cloud_cover,wind_speed_10m,wind_direction_10m',
        hourly: 'temperature_2m,precipitation_probability,precipitation,cloud_cover,rain',
        daily: 'temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max',
        temperature_unit: 'celsius',
        wind_speed_unit: 'kmh',
        timezone: 'auto',
        forecast_days: 7
      });

      const response = await fetch(`https://api.open-meteo.com/v1/forecast?${params}`);
      const data = await response.json();

      const transformedWeather = {
        current: {
          temperature: Math.round(data.current.temperature_2m),
          humidity: Math.round(data.current.relative_humidity_2m),
          rain: data.current.rain || 0,
          cloud_cover: Math.round(data.current.cloud_cover),
          wind_speed: Math.round(data.current.wind_speed_10m),
          wind_direction: data.current.wind_direction_10m,
          condition: getCondition(data.current.cloud_cover, data.current.rain)
        },
        hourly: data.hourly.time.slice(0, 24).map((time, i) => ({
          time: new Date(time).getHours() + ':00',
          temp: Math.round(data.hourly.temperature_2m[i]),
          precip: data.hourly.precipitation_probability[i] || 0,
          rain: data.hourly.rain[i] || 0,
          cloud: data.hourly.cloud_cover[i],
          icon: getWeatherIcon(data.hourly.cloud_cover[i], data.hourly.rain[i])
        })),
        daily: data.daily.time.slice(0, 7).map((time, i) => ({
          day: getDayName(time, i),
          high: Math.round(data.daily.temperature_2m_max[i]),
          low: Math.round(data.daily.temperature_2m_min[i]),
          precip: Math.round(data.daily.precipitation_sum[i]),
          precipProb: data.daily.precipitation_probability_max[i] || 0
        }))
      };

      setWeather(transformedWeather);
      checkForAlerts(transformedWeather);
    } catch (error) {
      console.error('Weather fetch error:', error);
    }
    setWeatherLoading(false);
  };

  const checkForAlerts = (weatherData) => {
    if (!weatherData || !user || user.role === 'admin') return;

    const alerts = [];
    const w = weatherData.current;

    // Critical alerts
    if (w.wind_speed > 45) {
      alerts.push({
        severity: 'critical',
        title: 'SEVERE WIND WARNING',
        message: `Dangerous winds of ${w.wind_speed} km/h detected in ${parish.name}`,
        action: 'Secure loose objects. Stay indoors. Avoid coastal areas.'
      });
    }

    // High alerts
    if (w.wind_speed > 25 && w.wind_speed <= 45) {
      alerts.push({
        severity: 'high',
        title: 'Strong Wind Advisory',
        message: `Wind speeds reaching ${w.wind_speed} km/h in ${parish.name}`,
        action: 'Exercise caution outdoors. Secure lightweight objects.'
      });
    }

    if (w.rain > 5) {
      alerts.push({
        severity: 'high',
        title: 'Heavy Rainfall Alert',
        message: `Heavy rain (${w.rain}mm/hr) affecting ${parish.name}`,
        action: 'Avoid low-lying areas. Monitor for flash flooding.'
      });
    }

    if (alerts.length > 0 && alertPrefs.storms) {
      // Save to history
      const newHistory = [...alertHistory, ...alerts.map(a => ({
        ...a,
        timestamp: new Date().toISOString(),
        parish: parish.name
      }))].slice(-50);
      setAlertHistory(newHistory);
      localStorage.setItem(`alert_history_${user.email}`, JSON.stringify(newHistory));
    }
  };

  const loadAlertHistory = () => {
    try {
      const stored = localStorage.getItem(`alert_history_${user.email}`);
      if (stored) {
        setAlertHistory(JSON.parse(stored));
      }
    } catch (e) {
      console.error('Error loading alerts:', e);
    }
  };

  const loadUsers = async () => {
    // In production, this would fetch from backend
    // For now, show placeholder
    setUsers([
      { id: 1, name: 'John Doe', email: 'john@example.com', parish: 'Saint George', alerts: true },
      { id: 2, name: 'Jane Smith', email: 'jane@example.com', parish: 'Saint Andrew', alerts: true },
    ]);
  };

  const sendBroadcastAlert = async () => {
    if (!broadcastMessage.trim()) {
      setError('Please enter a message');
      return;
    }

    setSending(true);
    setError('');

    // Simulate sending (in production, call backend)
    setTimeout(() => {
      setSuccess(`Alert sent to ${users.filter(u => u.alerts).length} users!`);
      setBroadcastMessage('');
      setSending(false);
      setTimeout(() => setSuccess(''), 3000);
    }, 1500);
  };

  const updateAlertPreferences = async (prefs) => {
    setAlertPrefs(prefs);
    // In production, save to backend via API
    const updatedUser = { ...user, alerts: prefs };
    setUser(updatedUser);
    localStorage.setItem('user', JSON.stringify(updatedUser));
    setSuccess('Preferences updated!');
    setTimeout(() => setSuccess(''), 2000);
  };

  const getCondition = (cloud, rain) => {
    if (rain > 2) return 'Heavy Rain';
    if (rain > 0) return 'Light Rain';
    if (cloud > 75) return 'Cloudy';
    if (cloud > 40) return 'Partly Cloudy';
    return 'Clear';
  };

  const getWeatherIcon = (cloud, rain) => {
    if (rain > 2) return '🌧️';
    if (rain > 0) return '🌦️';
    if (cloud > 75) return '☁️';
    if (cloud > 40) return '⛅';
    return '☀️';
  };

  const getDayName = (dateStr, index) => {
    if (index === 0) return 'Today';
    if (index === 1) return 'Tomorrow';
    return new Date(dateStr).toLocaleDateString('en-US', { weekday: 'short' });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_BASE}/login.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
        if (data.user.alerts) {
          setAlertPrefs(data.user.alerts);
        }
      } else {
        setError(data.error || 'Login failed');
      }
    } catch (err) {
      setError('Connection error. Make sure XAMPP Apache is running.');
    } finally {
      setFormLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_BASE}/register.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, name, phone, parish: 'saint-george' })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
        if (data.user.alerts) {
          setAlertPrefs(data.user.alerts);
        }
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Connection error.');
    } finally {
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    setWeather(null);
    setAlertHistory([]);
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user');
    setPage('login');
    setCurrentTab('weather');
  };

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
        <p>Loading WeatherAlert...</p>
      </div>
    );
  }

  // Login Page
  if (page === 'login' && !user) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="logo">🌅</div>
            <h1>WeatherAlert</h1>
            <p>Grenada Weather Monitoring System</p>
          </div>

          <form onSubmit={handleLogin} className="auth-form">
            <h2>Sign In</h2>

            {error && <div className="error-message">{error}</div>}

            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your.email@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter your password"
                required
              />
            </div>

            <button type="submit" className="btn-primary" disabled={formLoading}>
              {formLoading ? 'Signing in...' : 'Sign In'}
            </button>

            <p className="auth-link">
              Don't have an account? <a href="#" onClick={() => setPage('register')}>Register here</a>
            </p>

            <div className="admin-hint">
              <small>Admin: shenait0323@gmail.com / WeatherAdmin2024!</small>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // Register Page
  if (page === 'register' && !user) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="logo">🌅</div>
            <h1>WeatherAlert</h1>
            <p>Grenada Weather Monitoring System</p>
          </div>

          <form onSubmit={handleRegister} className="auth-form">
            <h2>Create Account</h2>

            {error && <div className="error-message">{error}</div>}

            <div className="form-group">
              <label>Full Name</label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="John Doe"
                required
              />
            </div>

            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your.email@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label>Phone (for SMS alerts)</label>
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="+1 473 XXX XXXX"
              />
            </div>

            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Choose a password"
                required
              />
            </div>

            <button type="submit" className="btn-primary" disabled={formLoading}>
              {formLoading ? 'Creating account...' : 'Register'}
            </button>

            <p className="auth-link">
              Already have an account? <a href="#" onClick={() => setPage('login')}>Sign in here</a>
            </p>
          </form>
        </div>
      </div>
    );
  }

  // Dashboard with Tabs
  return (
    <div className="dashboard" style={{background: isDark ? '#0f1117' : '#e3f2fd', minHeight: '100vh'}}>
      <nav className="navbar">
        <div className="navbar-brand">
          <span className="logo">🌅</span>
          <span>WeatherAlert</span>
        </div>
        <div className="navbar-menu">
          <select 
            value={parish.id} 
            onChange={(e) => setParish(PARISHES.find(p => p.id === e.target.value))}
            style={{padding: '8px 12px', borderRadius: '8px', border: '1px solid #ddd', marginRight: '15px'}}
          >
            {PARISHES.map(p => (
              <option key={p.id} value={p.id}>{p.name}</option>
            ))}
          </select>
          <span style={{color: '#666', marginRight: '15px'}}>Welcome, {user.name}!</span>
          {user.role === 'admin' && <span style={{background: '#667eea', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '12px', marginRight: '10px'}}>ADMIN</span>}
          <button onClick={() => setIsDark(!isDark)} style={{padding: '8px 12px', borderRadius: '8px', border: 'none', background: '#f0f0f0', marginRight: '10px', cursor: 'pointer'}}>{isDark ? '☀️' : '🌙'}</button>
          <button onClick={handleLogout} className="btn-logout">Logout</button>
        </div>
      </nav>

      {/* Tabs */}
      <div style={{background: 'white', borderBottom: '2px solid #e2e8f0', position: 'sticky', top: '60px', zIndex: 50}}>
        <div className="container" style={{padding: '0 20px'}}>
          <div style={{display: 'flex', gap: '5px'}}>
            <button 
              onClick={() => setCurrentTab('weather')} 
              style={{padding: '16px 24px', border: 'none', background: currentTab === 'weather' ? '#667eea' : 'transparent', color: currentTab === 'weather' ? 'white' : '#666', cursor: 'pointer', borderRadius: '8px 8px 0 0', fontWeight: '600', transition: 'all 0.2s'}}
            >
              🌤️ Weather
            </button>
            <button 
              onClick={() => setCurrentTab('alerts')} 
              style={{padding: '16px 24px', border: 'none', background: currentTab === 'alerts' ? '#667eea' : 'transparent', color: currentTab === 'alerts' ? 'white' : '#666', cursor: 'pointer', borderRadius: '8px 8px 0 0', fontWeight: '600', transition: 'all 0.2s'}}
            >
              🚨 My Alerts
            </button>
            {user.role === 'admin' && (
              <button 
                onClick={() => setCurrentTab('admin')} 
                style={{padding: '16px 24px', border: 'none', background: currentTab === 'admin' ? '#667eea' : 'transparent', color: currentTab === 'admin' ? 'white' : '#666', cursor: 'pointer', borderRadius: '8px 8px 0 0', fontWeight: '600', transition: 'all 0.2s'}}
              >
                👑 Admin Panel
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="container">
        {/* Weather Tab */}
        {currentTab === 'weather' && (
          weatherLoading ? (
            <div style={{textAlign: 'center', padding: '60px'}}>
              <div className="spinner"></div>
              <p>Loading weather data...</p>
            </div>
          ) : weather ? (
            <>
              {/* Current Weather */}
              <div className="weather-card">
                <div className="location">{parish.capital}, {parish.name}</div>
                <div className="temp">{weather.current.temperature}°</div>
                <div className="condition">{weather.current.condition}</div>
                <div className="stat-grid">
                  <div className="stat-item">
                    <div className="stat-label">Humidity</div>
                    <div className="stat-value">{weather.current.humidity}%</div>
                  </div>
                  <div className="stat-item">
                    <div className="stat-label">Wind</div>
                    <div className="stat-value">{weather.current.wind_speed} km/h</div>
                  </div>
                  <div className="stat-item">
                    <div className="stat-label">Cloud Cover</div>
                    <div className="stat-value">{weather.current.cloud_cover}%</div>
                  </div>
                  <div className="stat-item">
                    <div className="stat-label">Rain</div>
                    <div className="stat-value">{weather.current.rain.toFixed(1)} mm</div>
                  </div>
                </div>
              </div>

              {/* Hourly Forecast */}
              <div className="card">
                <h2>Hourly Forecast</h2>
                <div className="hourly-scroll">
                  {weather.hourly.slice(0, 12).map((h, i) => (
                    <div key={i} className="hourly-item">
                      <div className="hourly-time">{h.time}</div>
                      <div className="hourly-icon">{h.icon}</div>
                      <div className="hourly-temp">{h.temp}°</div>
                      <div className="hourly-precip">💧 {h.precip}%</div>
                    </div>
                  ))}
                </div>
              </div>

              {/* 7-Day Forecast */}
              <div className="card">
                <h2>7-Day Forecast</h2>
                {weather.daily.map((d, i) => (
                  <div key={i} className="daily-row">
                    <div className="daily-day">{d.day}</div>
                    <div className="daily-icon">☀️</div>
                    <div className="daily-temps">
                      <span className="daily-high">{d.high}°</span>
                      <span className="daily-low">{d.low}°</span>
                    </div>
                  </div>
                ))}
              </div>
            </>
          ) : (
            <div className="card">
              <p>Loading weather...</p>
            </div>
          )
        )}

        {/* Alerts Tab */}
        {currentTab === 'alerts' && (
          <>
            <div className="card">
              <h2>Alert Preferences</h2>
              {success && <div className="success-message">{success}</div>}
              <div style={{display: 'flex', gap: '20px', marginTop: '20px'}}>
                <label style={{display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer'}}>
                  <input 
                    type="checkbox" 
                    checked={alertPrefs.storms}
                    onChange={(e) => updateAlertPreferences({...alertPrefs, storms: e.target.checked})}
                    style={{width: '20px', height: '20px'}}
                  />
                  <span>Storm Alerts</span>
                </label>
                <label style={{display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer'}}>
                  <input 
                    type="checkbox" 
                    checked={alertPrefs.rain}
                    onChange={(e) => updateAlertPreferences({...alertPrefs, rain: e.target.checked})}
                    style={{width: '20px', height: '20px'}}
                  />
                  <span>Heavy Rain Alerts</span>
                </label>
              </div>
            </div>

            <div className="card">
              <h2>Alert History ({alertHistory.length})</h2>
              {alertHistory.length === 0 ? (
                <p style={{color: '#999'}}>No alerts received yet</p>
              ) : (
                <div style={{maxHeight: '500px', overflowY: 'auto'}}>
                  {alertHistory.slice().reverse().map((alert, i) => (
                    <div key={i} style={{padding: '15px', marginBottom: '10px', background: alert.severity === 'critical' ? '#fee' : '#fef3c7', borderRadius: '8px', borderLeft: `4px solid ${alert.severity === 'critical' ? '#dc2626' : '#f59e0b'}`}}>
                      <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '8px'}}>
                        <strong style={{color: alert.severity === 'critical' ? '#dc2626' : '#d97706'}}>{alert.title}</strong>
                        <span style={{fontSize: '12px', color: '#666'}}>{new Date(alert.timestamp).toLocaleString()}</span>
                      </div>
                      <p style={{marginBottom: '8px', color: '#333'}}>{alert.message}</p>
                      <p style={{fontSize: '14px', color: '#666'}}>→ {alert.action}</p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}

        {/* Admin Panel Tab */}
        {currentTab === 'admin' && user.role === 'admin' && (
          <>
            <div className="card">
              <h2>📊 System Statistics</h2>
              <div style={{display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginTop: '20px'}}>
                <div style={{padding: '20px', background: '#f0f9ff', borderRadius: '12px', textAlign: 'center'}}>
                  <div style={{fontSize: '36px', fontWeight: '700', color: '#0369a1'}}>{users.length}</div>
                  <div style={{color: '#075985', marginTop: '5px'}}>Total Users</div>
                </div>
                <div style={{padding: '20px', background: '#fef3c7', borderRadius: '12px', textAlign: 'center'}}>
                  <div style={{fontSize: '36px', fontWeight: '700', color: '#d97706'}}>{users.filter(u => u.alerts).length}</div>
                  <div style={{color: '#92400e', marginTop: '5px'}}>Active Alerts</div>
                </div>
                <div style={{padding: '20px', background: '#dcfce7', borderRadius: '12px', textAlign: 'center'}}>
                  <div style={{fontSize: '36px', fontWeight: '700', color: '#16a34a'}}>Online</div>
                  <div style={{color: '#166534', marginTop: '5px'}}>System Status</div>
                </div>
              </div>
            </div>

            <div className="card">
              <h2>📢 Broadcast Alert</h2>
              {success && <div className="success-message">{success}</div>}
              {error && <div className="error-message">{error}</div>}
              <div style={{marginTop: '20px'}}>
                <textarea
                  value={broadcastMessage}
                  onChange={(e) => setBroadcastMessage(e.target.value)}
                  placeholder="Enter alert message to send to all users..."
                  style={{width: '100%', minHeight: '120px', padding: '12px', borderRadius: '8px', border: '2px solid #e2e8f0', fontSize: '15px'}}
                />
                <button 
                  onClick={sendBroadcastAlert}
                  disabled={sending || !broadcastMessage.trim()}
                  style={{marginTop: '12px', padding: '12px 24px', background: sending ? '#ccc' : '#667eea', color: 'white', border: 'none', borderRadius: '8px', cursor: sending ? 'not-allowed' : 'pointer', fontWeight: '600'}}
                >
                  {sending ? 'Sending...' : `Send to ${users.filter(u => u.alerts).length} Users`}
                </button>
              </div>
            </div>

            <div className="card">
              <h2>👥 Registered Users ({users.length})</h2>
              <div style={{marginTop: '20px'}}>
                {users.map((u, i) => (
                  <div key={i} style={{padding: '12px', marginBottom: '8px', background: '#f8f9fa', borderRadius: '8px', display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                    <div>
                      <strong>{u.name}</strong>
                      <div style={{fontSize: '13px', color: '#666'}}>{u.email} • {u.parish}</div>
                    </div>
                    <span style={{padding: '4px 12px', background: u.alerts ? '#dcfce7' : '#fee', color: u.alerts ? '#166534' : '#991b1b', borderRadius: '6px', fontSize: '12px', fontWeight: '600'}}>
                      {u.alerts ? 'Alerts ON' : 'Alerts OFF'}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
